import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Trophy, Star, Sparkles, MapPin, CalendarDays } from "lucide-react";
import Link from "next/link";
// Si tenés el componente Countdown en otra ruta, importalo aquí:
// import { Countdown } from "@/components/ui/countdown"; 

export default function CentenarioPage() {
  return (
    <div className="min-h-screen bg-zinc-950 text-white font-sans selection:bg-amber-500 selection:text-black">
      
      {/* --- 1. HERO ÉPICO --- */}
      <section className="relative h-screen flex items-center justify-center overflow-hidden">
        {/* Fondo con Overlay Dorado */}
        <div 
          className="absolute inset-0 bg-[url('/images/centenario-bg.jpg')] bg-cover bg-center opacity-30 grayscale"
        />
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-zinc-950/60 to-zinc-950" />
        
        {/* Partículas / Efecto Brillo */}
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-red-600/20 blur-[120px] rounded-full" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-amber-500/10 blur-[120px] rounded-full" />

        <div className="container relative z-10 px-6 text-center">
          <Badge className="bg-amber-500 text-black rounded-none mb-8 uppercase font-black tracking-[0.4em] px-6 py-2 border-none animate-pulse">
            1927 • Rumbo a la Gloria • 2027
          </Badge>
          
          <h1 className="text-7xl md:text-[12rem] font-black uppercase tracking-tighter leading-[0.8] mb-8 italic">
            Huazihul <br /> 
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-amber-200 via-amber-500 to-amber-200 animate-gradient">
              100 Años
            </span>
          </h1>
          
          <p className="text-zinc-400 text-xl md:text-3xl max-w-3xl mx-auto font-light leading-relaxed mb-12">
            Un siglo de tacles, bochas, barro y pasión. El Cacique se prepara para su cita más importante con la historia.
          </p>

          {/* ESPACIO PARA EL COUNTDOWN */}
          <div className="max-w-4xl mx-auto bg-white/5 backdrop-blur-md border border-white/10 p-8 md:p-12 rounded-[3rem] shadow-2xl shadow-amber-500/5">
             <p className="text-amber-500 font-black uppercase tracking-[0.5em] text-xs mb-8">Faltan para el Centenario</p>
             {/* Aquí va tu componente Countdown o un placeholder imponente */}
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4 md:gap-8">
                {[
                  { label: "Días", value: "342" },
                  { label: "Horas", value: "12" },
                  { label: "Minutos", value: "45" },
                  { label: "Segundos", value: "08" },
                ].map((item, i) => (
                  <div key={i} className="flex flex-col">
                    <span className="text-5xl md:text-7xl font-black italic text-white leading-none">{item.value}</span>
                    <span className="text-[10px] font-bold uppercase tracking-widest text-zinc-500 mt-2">{item.label}</span>
                  </div>
                ))}
             </div>
          </div>
        </div>
      </section>

      {/* --- 2. LA VISIÓN DEL SIGLO --- */}
      <section className="py-24 md:py-40 bg-zinc-950">
        <div className="container px-6 md:px-8">
          <div className="grid lg:grid-cols-2 gap-24 items-center">
            <div className="space-y-8">
              <div className="w-20 h-2 bg-amber-500" />
              <h2 className="text-5xl md:text-7xl font-black uppercase tracking-tighter leading-none italic">
                El Sueño de <br /> <span className="text-amber-500">Los Pioneros</span>
              </h2>
              <p className="text-zinc-400 text-lg md:text-xl font-light leading-relaxed">
                Lo que comenzó en el Bar Alemán en 1927 se convirtió en la institución más grande de la región. El centenario no es solo una fecha, es el reconocimiento a cada jugador, socia y familia que empujó el scrum de nuestra historia.
              </p>
              <div className="flex flex-col gap-6">
                <div className="flex items-center gap-4 group">
                  <div className="w-12 h-12 rounded-2xl bg-zinc-900 flex items-center justify-center group-hover:bg-amber-500 transition-colors">
                    <Trophy className="text-amber-500 group-hover:text-black transition-colors" />
                  </div>
                  <span className="text-sm font-bold uppercase tracking-widest">Cena de Gala 100 Aniversario</span>
                </div>
                <div className="flex items-center gap-4 group">
                  <div className="w-12 h-12 rounded-2xl bg-zinc-900 flex items-center justify-center group-hover:bg-amber-500 transition-colors">
                    <Star className="text-amber-500 group-hover:text-black transition-colors" />
                  </div>
                  <span className="text-sm font-bold uppercase tracking-widest">Museo Itinerante Cacique</span>
                </div>
              </div>
            </div>

            {/* IMAGEN DE IMPACTO */}
            <div className="relative group">
              <div className="absolute -inset-4 bg-amber-500/20 blur-2xl group-hover:bg-amber-500/30 transition-all rounded-full" />
              <div className="relative aspect-square bg-zinc-900 rounded-[4rem] overflow-hidden border border-white/10 shadow-2xl">
                <img 
                  src="/images/centenario-emblema.png" 
                  alt="Centenario Huazihul"
                  className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700"
                />
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* --- 3. EVENTOS DEL AÑO (TIMELINE) --- */}
      <section className="py-24 bg-white text-zinc-900 rounded-[4rem] md:rounded-[6rem] mx-2 md:mx-4">
        <div className="container px-6 md:px-8">
          <div className="text-center mb-24">
            <h2 className="text-5xl md:text-7xl font-black uppercase tracking-tighter italic mb-4">Agenda del <span className="text-red-600">Siglo</span></h2>
            <p className="text-zinc-500 uppercase tracking-widest text-sm font-black">Eventos confirmados camino al 2027</p>
          </div>

          <div className="grid md:grid-cols-3 gap-8">
            {[
              { 
                date: "Junio 2026", 
                event: "Lanzamiento Camiseta Edición Especial",
                desc: "Un diseño inspirado en el Bar Alemán de 1927."
              },
              { 
                date: "Noviembre 2026", 
                event: "Torneo Nacional de Veteranos",
                desc: "Los Caciques reciben a todo el país en casa."
              },
              { 
                date: "Marzo 2027", 
                event: "Gran Fiesta del Centenario",
                desc: "La noche más esperada. El club unido para celebrar un siglo."
              }
            ].map((item, i) => (
              <div key={i} className="p-10 bg-zinc-50 rounded-[3rem] border border-zinc-100 hover:shadow-xl transition-all group">
                <CalendarDays className="w-10 h-10 text-red-600 mb-6 group-hover:scale-110 transition-transform" />
                <span className="text-red-600 font-black uppercase text-xs tracking-[0.2em]">{item.date}</span>
                <h3 className="text-2xl font-black uppercase tracking-tighter mt-4 mb-4 leading-none">{item.event}</h3>
                <p className="text-zinc-500 font-light text-sm">{item.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* --- 4. CTA FINAL --- */}
      <section className="py-32 text-center">
        <div className="container px-6">
          <Sparkles className="w-12 h-12 text-amber-500 mx-auto mb-8 animate-bounce" />
          <h2 className="text-5xl md:text-7xl font-black uppercase tracking-tighter mb-12 italic">
            No te quedes afuera <br /> de los <span className="text-amber-500">100</span>
          </h2>
          <div className="flex flex-col sm:flex-row justify-center gap-4">
            <Button className="bg-amber-500 hover:bg-white text-black rounded-none font-black uppercase tracking-widest px-12 h-16 transition-all" asChild>
              <Link href="/contacto">Colaborar con el Club</Link>
            </Button>
            <Button variant="outline" className="border-white text-white hover:bg-red-600 hover:border-red-600 rounded-none font-black uppercase tracking-widest px-12 h-16 transition-all" asChild>
              <Link href="/socios">Hacete Socio</Link>
            </Button>
          </div>
        </div>
      </section>
    </div>
  );
}